// Tests for <string_view> and char_traits.
// Each free function is named test_string_view_<case> or test_char_traits_<case>.
// Uses CHECK (runtime, traps on failure) and static_assert (compile-time).
// No progress printing; no main() (generated by tools/gen_main.sh).
#include <string_view>
#include "../test/test.h"

using namespace std;

//===----------------------------------------------------------------------===//
// char_traits<char>
//===----------------------------------------------------------------------===//

void test_char_traits_char_eq_lt() {
    static_assert(char_traits<char>::eq('a', 'a'));
    static_assert(!char_traits<char>::eq('a', 'b'));
    static_assert(char_traits<char>::lt('a', 'b'));
    static_assert(!char_traits<char>::lt('b', 'a'));
    // Signed char sign-extension: 0x80 vs 0x01 — unsigned semantics
    static_assert(char_traits<char>::lt('\x01', '\x80'));
    static_assert(!char_traits<char>::lt('\x80', '\x01'));
}

void test_char_traits_char_compare() {
    constexpr const char* a = "hello";
    constexpr const char* b = "hello";
    constexpr const char* c = "hellp";
    static_assert(char_traits<char>::compare(a, b, 5) == 0);
    static_assert(char_traits<char>::compare(a, c, 5) < 0);
    static_assert(char_traits<char>::compare(c, a, 5) > 0);
    static_assert(char_traits<char>::compare(a, b, 0) == 0);
}

void test_char_traits_char_length() {
    static_assert(char_traits<char>::length("") == 0);
    static_assert(char_traits<char>::length("hello") == 5);
    static_assert(char_traits<char>::length("hi there") == 8);
}

void test_char_traits_char_find() {
    constexpr const char* s = "hello";
    static_assert(char_traits<char>::find(s, 5, 'l') == s + 2);
    static_assert(char_traits<char>::find(s, 5, 'z') == nullptr);
    static_assert(char_traits<char>::find(s, 5, 'h') == s);
    static_assert(char_traits<char>::find(s, 5, 'o') == s + 4);
    static_assert(char_traits<char>::find(s, 0, 'h') == nullptr);
}

void test_char_traits_char_assign() {
    char c1 = 'a';
    char_traits<char>::assign(c1, 'z');
    CHECK(c1 == 'z');

    char buf[5] = {};
    char_traits<char>::assign(buf, 5, 'x');
    for (int i = 0; i < 5; ++i)
        CHECK(buf[i] == 'x');
}

void test_char_traits_char_copy_move() {
    char src[] = "hello";
    char dst[6] = {};
    char_traits<char>::copy(dst, src, 5);
    CHECK(char_traits<char>::compare(dst, src, 5) == 0);

    // move: overlapping forward
    char buf[] = "abcde";
    char_traits<char>::move(buf + 1, buf, 4);
    CHECK(buf[0] == 'a');
    CHECK(buf[1] == 'a');
    CHECK(buf[2] == 'b');
}

void test_char_traits_char_eof() {
    static_assert(char_traits<char>::eof() == EOF);
    auto e = char_traits<char>::eof();
    CHECK(!char_traits<char>::eq_int_type(char_traits<char>::not_eof(e), e));
    auto c = char_traits<char>::to_int_type('A');
    CHECK(char_traits<char>::not_eof(c) == c);
}

void test_char_traits_char_to_types() {
    constexpr auto i = char_traits<char>::to_int_type('\xFF');
    static_assert(i == 255); // unsigned char semantics
    constexpr auto ch = char_traits<char>::to_char_type(65);
    static_assert(ch == 'A');
}

//===----------------------------------------------------------------------===//
// char_traits<wchar_t>
//===----------------------------------------------------------------------===//

void test_char_traits_wchar_basic() {
    static_assert(char_traits<wchar_t>::eq(L'a', L'a'));
    static_assert(!char_traits<wchar_t>::eq(L'a', L'b'));
    static_assert(char_traits<wchar_t>::lt(L'a', L'b'));
    static_assert(char_traits<wchar_t>::length(L"hello") == 5);
    static_assert(char_traits<wchar_t>::length(L"") == 0);

    constexpr const wchar_t* s = L"hello";
    static_assert(char_traits<wchar_t>::compare(s, L"hello", 5) == 0);
    static_assert(char_traits<wchar_t>::compare(s, L"hellp", 5) < 0);
    static_assert(char_traits<wchar_t>::find(s, 5, L'l') == s + 2);
    static_assert(char_traits<wchar_t>::find(s, 5, L'z') == nullptr);
}

